def find_parity(lst):
    """
    Given a list of integers, return a dictionary where the keys are the unique elements in the list and the values are their respective parities (0 for even, 1 for odd).

    For example:
    find_parity([1, 2, 3, 4]) -> {1: 1, 2: 0, 3: 1, 4: 0}
    find_parity([-1, -2, 0]) -> {-1: 1, -2: 0, 0: 0}
    find_parity([1, 3, 5, 7]) -> {1: 1, 3: 1, 5: 1, 7: 1}
    find_parity([2, 4, 6, 8]) -> {2: 0, 4: 0, 6: 0, 8: 0}
    """

    parity_dict = {}
    for num in lst:
        if num not in parity_dict:
            parity_dict[num] = num % 2

    return parity_dict
